mapper.insert:
/** CmmtSmsDao.insert */
insert into cmmt_sms (
	 sms_id
	,mobile_no
	,message
	,send
	,send_dt
	,try_cnt
	,system_id
	,created_dt
) values (
	 #{smsId}
	,#{mobileNo}
	,#{message}
	,#{send}
	,#{sendDt}
	,#{tryCnt}
	,#{systemId}
	,#{createdDt}
)

/** CmmtSmsDao.insertList */
insert into cmmt_sms (
	 sms_id
	,mobile_no
	,message
	,send
	,send_dt
	,try_cnt
	,system_id
	,created_dt
) values

	(
		 #{item.smsId}
		,#{item.mobileNo}
		,#{item.message}
		,#{item.send}
		,#{item.sendDt}
		,#{item.tryCnt}
		,#{item.systemId}
		,#{item.createdDt}
	)

mapper.update:
/** CmmtSmsDao.update */
update cmmt_sms set
	 mobile_no  = #{mobileNo}
	,message    = #{message}
	,send       = #{send}
	,send_dt    = #{sendDt}
	,try_cnt    = #{tryCnt}
	,system_id  = #{systemId}
	,created_dt = #{createdDt}
where
	sms_id = #{smsId}

mapper.delete:
/** CmmtSmsDao.delete */
delete from
	cmmt_sms
where
	sms_id = #{smsId}

mapper.select:
/** CmmtSmsDao.select */
select

from
	cmmt_sms
where
	sms_id = #{smsId}

/** CmmtSmsDao.selectList_notSent */
select

from
	cmmt_sms
where

	send = false
	and created_dt >= #{fromDt}
	and try_cnt < #{maxTryCnt}

order by
	created_dt

mapper.delete:
/** CmmtSmsDao.delete_old */
delete from
	cmmt_sms
where

	created_dt <= #{dtime}
